# -*- coding: utf-8 -*-
import sys
from io import BytesIO


def solve(a, b):
    n = len(a)
    ans = 0
    for i in range(n):
        for j in range(i, n):
            if a[i] == b[j]:
                ans = max(ans, j - i + 1)
    return ans


def main():
    n = int(input())
    a, b = [], []
    for i in range(n):
        a_i, b_i = map(int, input().split())
        a.append(a_i)
        b.append(b_i)
    print(solve(a, b))


if __name__ == '__main__':
    main()
